INSERT INTO brands (slug, name, category_slug, gonogo_score, verdict, logo_url, website_url, framework_breakdown, key_features, pricing, app_ratings, key_strengths, key_concerns, social_sentiment, last_updated) VALUES ('keyhealth-medical-scheme', 'KeyHealth Medical Scheme', 'medical-aid', 60, 'GO WITH CAUTION', 'https://t0.gstatic.com/faviconV2?client=SOCIAL&type=FAVICON&fallback_opts=TYPE,SIZE,URL&url=https://www.keyhealth.co.za&size=128', 'https://www.keyhealth.co.za', $json$[{"category":"Compliance","score":"18/20","description":"CMS registered #1087; no penalties, complaints to CMS possible; standard medical scheme regulation."},{"category":"Customer Satisfaction","score":"8/20","description":"HelloPeter 2.6/5 (65 reviews, 89% 1-star); avg 3.8/5 cited elsewhere; dominant complaints on claims/service."},{"category":"Product Value","score":"25/30","description":"Competitive pricing vs larger schemes, unlimited hospital/PMBs/chronic (26-55), maternity/dental, but DSP req, co-pays non-DSP, limited day-to-day on basic plans."},{"category":"Innovation","score":"5/10","description":"Member app for cards/claims/hospitals/newborn reg (buggy); KEYHEALTH REWARDS, Health Booster, Smart Baby, Easy-ER programs; digital claims/portal."},{"category":"Customer Support","score":"6/15","description":"0860 671 050 (7:30-18:00 Mon-Fri), WhatsApp 0609768319, email; reviews cite unresponsiveness, no callbacks."},{"category":"Accessibility & Security","score":"7/10","description":"App provides digital access to cards/claims/hospitals; collects personal data (not encrypted per Play store); no POPIA breaches or security issues found in searches."}]$json$::jsonb, $json$["unlimited hospital (DSP)","PMB/chronic cover","Health Booster screenings","Smart Baby maternity","Easy-ER emergency access","dental/optical benefits"]$json$::jsonb, $json$[{"name":"Pricing","cost":"Pricing: From R2187/mo (Essence main) to R13840/mo (Platinum); Gold R8675","features":""}]$json$::jsonb, $json${"google_play"