INSERT INTO brands (slug, name, category_slug, gonogo_score, verdict, logo_url, website_url, framework_breakdown, key_features, pricing, app_ratings, key_strengths, key_concerns, social_sentiment, last_updated) VALUES ('bonitas', 'Bonitas', 'medical-aid', 63, 'GO WITH CAUTION', 'https://cdn.brandfetch.io/id09_HhDWT/w/258/h/100/theme/dark/logo.png', 'https://www.bonitas.co.za', $json$[{"category":"Compliance","score":"15/20","description":"CMS registered #1512; strong solvency 38.6%; AA+ rating; under CMS s44 forensic investigation for governance/procurement (ongoing 2026 court case with Medscheme), no penalties yet but raises concerns."},{"category":"Customer Satisfaction","score":"10/20","description":"Low ratings: HelloPeter 1.73/5 (Trust Index 4.2), app reviews highlight frustrations despite some positive care stories."},{"category":"Product Value","score":"25/30","description":"Competitive pricing across spectrum, good value in hospital/chronic cover, network savings; some plans loss-making but reserves support."},{"category":"Innovation","score":"7/10","description":"Member app with virtual consults, chat, digital card, wellness tools, authorizations; care programs for chronic/cancer; digital health initiatives."},{"category":"Customer Support","score":"9/15","description":"App chat 8am-8pm Mon-Fri/Sat; phone support; mixed reviews - quick claims praised but frequent complaints on delays/responsiveness."},{"category":"Accessibility & Security","score":"7/10","description":"POPIA compliant with dedicated policy and consent processes; app with digital access but poor usability reports; no known breaches; encrypted data practices in app."}]$json$::jsonb, $json$["Hospital plans from R1275","comprehensive up to R12509","chronic 27-60 conditions","network options","digital app","oncology/maternity programs"]$json$::jsonb, $json$[{"name":"Pricing","cost":"Pricing: From R1,275/mo (BonCore hospital) to R12,509/mo (BonComprehensive); child rates ~R800-R2500","features":""}]$json$::jsonb, $json${"google_play":"1.9/5","ios":"2.0/5 (est. from reviews)"}$json$::jsonb, $json$["Affordable entry plans","strong solvency/reserves","wide plan range","high hospital claims payment speed"]$json$::jsonb, $json$["Ongoing regulatory probe","low review ratings","app unreliability"]$json$::jsonb, $json${"summary":"Mixed; positive on financial strength/pricing, negative on service/app from HelloPeter/Google; news focuses on governance disputes.","positive_themes":["affordable pricing","good hospital cover","benefit enhancements","strong financials"],"common_concerns":["claims delays","poor app functionality","customer service response times","governance scrutiny"]}$json$::jsonb, '2026-03-05') ON CONFLICT (slug) DO UPDATE SET name=EXCLUDED.name, category_slug=EXCLUDED.category_slug, gonogo_score=EXCLUDED.gonogo_score, verdict=EXCLUDED.verdict, logo_url=EXCLUDED.logo_url, website_url=EXCLUDED.website_url, framework_breakdown=EXCLUDED.framework_breakdown, key_features=EXCLUDED.key_features, pricing=EXCLUDED.pricing, app_ratings=EXCLUDED.app_ratings, key_strengths=EXCLUDED.key_strengths, key_concerns=EXCLUDED.key_concerns, social_sentiment=EXCLUDED.social_sentiment, last_updated=EXCLUDED.last_updated;
